import{_ as a}from"./chunks/3d-camera-control.DebWnGgC.js";import{_ as r,C as o,o as d,c as s,E as i,a2 as n}from"./chunks/framework.CkaEw-3u.js";const _=JSON.parse('{"title":"3Dタイポグラフィを作る","description":"カメラ、遠近感、文字・パーツの奥行きを使った3Dタイポグラフィ制作","frontmatter":{"title":"3Dタイポグラフィを作る","description":"カメラ、遠近感、文字・パーツの奥行きを使った3Dタイポグラフィ制作","pageClass":"feature-guide","aside":false},"headers":[],"relativePath":"features/feature-3d.md","filePath":"features/feature-3d.md"}'),l={name:"features/feature-3d.md"};function c(h,t,p,g,f,m){const e=o("FeatureHero");return d(),s("div",null,[i(e,{eyebrow:"3D TYPOGRAPHY",title:"奥行き感のある、パースの効いた表現",description:"テキスト全体を平面として傾けるだけでなく、文字やパーツを奥行き方向へ配置。専用カメラと遠近感を組み合わせ、2Dの操作感を保ったまま立体的なタイポグラフィを作れます。",image:"/image/3d-typography.webp","image-alt":"遠近感と文字ごとの奥行きを使った3Dタイポグラフィ（準備中）","detail-link":"/reference/reference-camera-settings","detail-label":"Camera Settings","point-one":"ビューアでカメラ操作","point-two":"文字・パーツの奥行き","point-three":"既存エフェクトと併用"}),t[0]||(t[0]=n('<h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><ol><li>エフェクトライブラリから <strong>Mug Typography 3D</strong> または <strong>Mug Typography Lite (3D)</strong> を配置します。</li><li><strong>Selection Mode</strong> を <code>Camera</code> に切り替えます。</li><li>ビューアのOrbitハンドル、または空白部分の<code>Alt</code>ドラッグでカメラを回します。</li><li>必要に応じて <strong>Camera Settings</strong> の <strong>Perspective Strength</strong> と <strong>Camera Zoom</strong> で画角を仕上げます。</li></ol><p><img src="'+a+'" alt="Camera Controlインタラクション"></p><h2 id="_3d版とlite-3d版" tabindex="-1">3D版とLite 3D版 <a class="header-anchor" href="#_3d版とlite-3d版" aria-label="Permalink to &quot;3D版とLite 3D版&quot;">​</a></h2><table tabindex="0"><thead><tr><th>プリセット</th><th style="text-align:right;">最大文字数</th><th>パーツ設定</th><th>向いている用途</th></tr></thead><tbody><tr><td><strong>Mug Typography 3D</strong></td><td style="text-align:right;">30</td><td>最大84パーツ</td><td>パーツごとに奥行きを付ける立体表現</td></tr><tr><td><strong>Mug Typography Lite (3D)</strong></td><td style="text-align:right;">45</td><td>なし</td><td>文字単位の3D表現、長めのテキスト</td></tr></tbody></table><p>どちらも通常のMidプリセットを基準にした上限です。Lite 3DはPart Settingsを省略し、最大512パーツまで描画できますが、パーツ単位のZ Offsetは編集できません。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>最大文字数・最大パーツ数の上限は、<code>preferences.json</code> の <code>maxCharacters</code> / <code>maxParts</code> で変更できます。調整方法は付録の「<a href="/mug-typography-docs/reference/appendix.html#環境設定のカスタマイズ-preferences-json">環境設定のカスタマイズ (preferences.json)</a>」を参照してください。</p></div><h2 id="_3つの階層で立体感を作る" tabindex="-1">3つの階層で立体感を作る <a class="header-anchor" href="#_3つの階層で立体感を作る" aria-label="Permalink to &quot;3つの階層で立体感を作る&quot;">​</a></h2><table tabindex="0"><thead><tr><th>階層</th><th>3D専用パラメーター</th><th>役割</th></tr></thead><tbody><tr><td><strong>Global</strong></td><td>Global Yaw / Global Pitch</td><td>テキスト全体の平面を傾ける</td></tr><tr><td><strong>Character</strong></td><td>Z Offset / Yaw / Pitch</td><td>文字ごとに奥行きと向きを変える</td></tr><tr><td><strong>Part</strong></td><td>Z Offset</td><td>点や画を前後へ分離する</td></tr><tr><td><strong>Camera</strong></td><td>Target / Yaw / Pitch / Perspective / Zoom / Lens Shift</td><td>シーンを見る位置と投影を決める</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>まずGlobal Yaw/Pitchで全体の向きを決め、次に文字のZ Offsetで前後差を作り、最後にカメラを調整すると迷いにくくなります。</p></div><h2 id="_2d版との違い" tabindex="-1">2D版との違い <a class="header-anchor" href="#_2d版との違い" aria-label="Permalink to &quot;2D版との違い&quot;">​</a></h2><p>3Dプリセットでは、Character Settingsの <strong>Stretch</strong> が <strong>Z Offset / Yaw / Pitch</strong> に置き換わります。Part SettingsではStretchがZ Offsetに置き換わります。Position、Pivot、Scale、Rotationや、カラー・ストロークなどの既存設定は引き続き使用できます。</p><p>グラデーション、シャドウ、バウンディングボックス、デフォーム、モーフ、Write Onも3D投影後の見た目へ追従します。</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>現在、Copy / Pasteページの「選択範囲をコピー」では、Z Offset / Yaw / Pitchを個別の貼り付け対象に選べません。</p></div><h2 id="ビューア上での操作" tabindex="-1">ビューア上での操作 <a class="header-anchor" href="#ビューア上での操作" aria-label="Permalink to &quot;ビューア上での操作&quot;">​</a></h2><p>Selection Mode が <code>Global</code> / <code>Character</code> / <code>Part</code> のとき、テキストは<strong>カメラ設定を適用する前の状態</strong>で表示されます。移動・回転・スケールなどのビューア操作も、この状態の2D座標に対して行われます。カメラで付けた傾きや遠近感に惑わされることなく、2Dプリセットと同じ感覚でレイアウトを編集できます。</p><p>カメラを含めた最終的な構図を確認・調整するには、Selection Mode を <code>Camera</code> に切り替えます。</p>',17))])}const P=r(l,[["render",c]]);export{_ as __pageData,P as default};
